import{_ as t,o as e,c as r,Q as a}from"./chunks/framework.3daba8ea.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/业务框架/DTM/TCC.md","filePath":"packages/doc/src/业务框架/DTM/TCC.md","lastUpdated":1702458087000}'),n={name:"doc/业务框架/DTM/TCC.md"},o=a('<p>TCC事务模式</p><p>什么是TCC，TCC是Try、Confirm、Cancel三个词语的缩写，最早是由 Pat Helland 于 2007 年发表的一篇名为《Life beyond Distributed Transactions:an Apostate’s Opinion》的论文提出。</p><p><a href="https://www.dtm.pub/practice/tcc.html#tcc%E7%BB%84%E6%88%90" target="_blank" rel="noreferrer">#</a>TCC组成</p><p>TCC分为3个阶段</p><ul><li>Try 阶段：尝试执行，完成所有业务检查（一致性）, 预留必须业务资源（准隔离性）</li><li>Confirm 阶段：如果所有分支的Try都成功了，则走到Confirm阶段。Confirm真正执行业务，不作任何业务检查，只使用 Try 阶段预留的业务资源</li><li>Cancel 阶段：如果所有分支的Try有一个失败了，则走到Cancel阶段。Cancel释放 Try 阶段预留的业务资源。</li></ul><p>如果我们要进行一个类似于银行跨行转账的业务，转出（TransOut）和转入（TransIn）分别在不同的微服务里，一个成功完成的TCC事务典型的时序图如下：</p><p>​ <img src="https://note.youdao.com/yws/public/resource/db319b4f392066045379fd763f5437a5/xmlnote/80399A4D3FAB474AB4F6B468E8238B47/30381" alt="0"></p><p>失败：</p><p>​ <img src="https://note.youdao.com/yws/public/resource/db319b4f392066045379fd763f5437a5/xmlnote/93500C6A7F7D40E987C3C98EAB23E410/30385" alt="0"></p><p><strong>Confirm/Cancel操作异常</strong></p><p>假如Confirm/Cancel操作遇见失败会怎么样？按照Tcc模式的协议，Confirm/Cancel操作是不允许失败的，遇见失败的情况，都是由于临时故障或者程序bug。dtm在Confirm/Cancel操作遇见失败时，会不断进行重试，直到成功。</p><p>为了避免程序bug导致补偿操作一直无法成功，建议开发者对全局事务表进行监控，发现重试超过3次的事务，发出报警，由运维人员找开发手动处理</p><p><strong>嵌套的TCC</strong></p><p>子事务嵌套时，从传入的请求中构建tcc对象，然后就能够正常使用tcc对象，进行相关的事务。</p>',14),c=[o];function p(s,C,i,l,T,d){return e(),r("div",null,c)}const f=t(n,[["render",p]]);export{m as __pageData,f as default};
